import React, { useState } from "react";
import doctorService from "../../services/doctor.service";

const emptyMedicine = {
  medicineName: "",
  dosage: "",
  frequency: "",
  duration: "",
  instructions: ""
};

const initialPrescription = {
  patientId: "",
  appointmentId: "",
  diagnosis: "",
  notes: "",
  validUntil: "",
  medicines: [{ ...emptyMedicine }]
};

function IssuePrescription() {
  const [doctorId, setDoctorId] = useState("");
  const [form, setForm] = useState(initialPrescription);
  const [prescriptions, setPrescriptions] = useState([]);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const setFeedback = (ok, text) => {
    setMessage(ok ? text : "");
    setError(ok ? "" : text);
  };

  const updateMedicine = (index, key, value) => {
    setForm((prev) => {
      const medicines = [...prev.medicines];
      medicines[index] = { ...medicines[index], [key]: value };
      return { ...prev, medicines };
    });
  };

  const addMedicine = () => {
    setForm((prev) => ({ ...prev, medicines: [...prev.medicines, { ...emptyMedicine }] }));
  };

  const removeMedicine = (index) => {
    setForm((prev) => ({
      ...prev,
      medicines: prev.medicines.filter((_, idx) => idx !== index)
    }));
  };

  const loadPrescriptions = async () => {
    if (!doctorId) {
      setFeedback(false, "Doctor ID is required.");
      return;
    }
    try {
      const response = await doctorService.getPrescriptions(doctorId);
      setPrescriptions(response.data || []);
      setFeedback(true, "Prescription list loaded.");
    } catch (err) {
      setFeedback(false, err.response?.data?.message || "Failed to load prescriptions.");
    }
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (!doctorId) {
      setFeedback(false, "Doctor ID is required.");
      return;
    }

    try {
      await doctorService.issuePrescription(doctorId, {
        ...form,
        patientId: Number(form.patientId),
        appointmentId: Number(form.appointmentId),
        validUntil: form.validUntil
      });
      setFeedback(true, "Prescription issued successfully.");
      setForm(initialPrescription);
      await loadPrescriptions();
    } catch (err) {
      setFeedback(false, err.response?.data?.message || "Failed to issue prescription.");
    }
  };

  return (
    <section className="card">
      <h2>Issue Prescription</h2>

      <div className="inline-row">
        <input
          placeholder="Doctor ID"
          value={doctorId}
          onChange={(e) => setDoctorId(e.target.value)}
        />
        <button type="button" onClick={loadPrescriptions}>Load Existing</button>
      </div>

      <form onSubmit={handleSubmit} className="grid-form">
        <input
          placeholder="Patient ID"
          value={form.patientId}
          onChange={(e) => setForm((prev) => ({ ...prev, patientId: e.target.value }))}
          required
        />
        <input
          placeholder="Appointment ID"
          value={form.appointmentId}
          onChange={(e) => setForm((prev) => ({ ...prev, appointmentId: e.target.value }))}
          required
        />
        <input
          placeholder="Diagnosis"
          value={form.diagnosis}
          onChange={(e) => setForm((prev) => ({ ...prev, diagnosis: e.target.value }))}
        />
        <input
          placeholder="Notes"
          value={form.notes}
          onChange={(e) => setForm((prev) => ({ ...prev, notes: e.target.value }))}
        />
        <input
          type="datetime-local"
          value={form.validUntil}
          onChange={(e) => setForm((prev) => ({ ...prev, validUntil: e.target.value }))}
          required
        />

        <h3>Medicines</h3>
        {form.medicines.map((medicine, index) => (
          <div className="medicine-box" key={`medicine-${index}`}>
            <input
              placeholder="Medicine Name"
              value={medicine.medicineName}
              onChange={(e) => updateMedicine(index, "medicineName", e.target.value)}
              required
            />
            <input
              placeholder="Dosage"
              value={medicine.dosage}
              onChange={(e) => updateMedicine(index, "dosage", e.target.value)}
            />
            <input
              placeholder="Frequency"
              value={medicine.frequency}
              onChange={(e) => updateMedicine(index, "frequency", e.target.value)}
            />
            <input
              placeholder="Duration"
              value={medicine.duration}
              onChange={(e) => updateMedicine(index, "duration", e.target.value)}
            />
            <input
              placeholder="Instructions"
              value={medicine.instructions}
              onChange={(e) => updateMedicine(index, "instructions", e.target.value)}
            />
            <button type="button" onClick={() => removeMedicine(index)} disabled={form.medicines.length === 1}>
              Remove
            </button>
          </div>
        ))}

        <div className="inline-row">
          <button type="button" onClick={addMedicine}>Add Medicine</button>
          <button type="submit">Issue Prescription</button>
        </div>
      </form>

      {message && <p className="ok">{message}</p>}
      {error && <p className="error">{error}</p>}

      <h3>Issued Prescriptions</h3>
      <pre className="result">{JSON.stringify(prescriptions, null, 2)}</pre>
    </section>
  );
}

export default IssuePrescription;
